import {useState} from "react";
import DATA_TAGS from "../DataTags.js";
import "./DataTagInput.scss";

export default function DataTagInput({style, addTag, addButton}) {
    const [_tag, _setTag] = useState("");
    const [selectTags, setSelectTags] = useState([]);

    const onChangeFilterTag = (e) => { 
        const value = e.target.value.toLocaleLowerCase();
        if (value !== "") {
            const filter = Object.keys(DATA_TAGS).filter(tag => {
                const re = new RegExp(value);
                return re.test(tag);
            });
            setSelectTags(() => filter);
        } else {
            setSelectTags(() => []);
        }
        _setTag(() => value);
    }

    const onClickPosibleTag = (tag) => {
        addTag(tag.trim());
        setSelectTags(() => []);
        _setTag(() => "");
    }

    return (
        <>
            <div className="data-tag" style={style}>
                <input 
                    style={{width: "100%"}}
                    className="p-2"
                    type="text" 
                    placeholder="add a tag"
                    value={_tag}
                    onChange={onChangeFilterTag}
                />
                {selectTags.length > 0 && (
                    <div className="select-tag p-2 br-2 flex-row flex-wrap align-c justify-c" style={{width: "100%"}}>
                        {selectTags.map(tag => (
                            <button 
                            key={"select-" + tag}
                            type="button"
                            className="posible-tag p-2"
                            onClick={() => onClickPosibleTag(tag)}
                            >
                                {tag}
                            </button>
                        ))}
                    </div>
                )}
            </div>
            {addButton && (
                <button 
                    className="data-tag_button br-2 p-2" 
                    type="button" 
                    onClick={() => onClickPosibleTag(_tag)}
                >
                    add
                </button>
            )}
        </>
    );
}
